#include <stdio.h>
#include <string.h>

#define MAXN 100005
#define ALPH 26

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N, D; scanf("%d %d", &N, &D);
        static char A[MAXN], B[MAXN];
        scanf("%s %s", A, B);
        // allocate count array dynamically to fit D
        int cnt[D][ALPH];
        for (int i = 0; i < D; ++i) for (int j = 0; j < ALPH; ++j) cnt[i][j] = 0;
        for (int i = 0; i < N; ++i) {
            int r = i % D;
            cnt[r][A[i] - 'a']++;
            cnt[r][B[i] - 'a']--;
        }
        int ok = 1;
        for (int i = 0; i < D && ok; ++i) {
            for (int j = 0; j < ALPH; ++j) {
                if (cnt[i][j] != 0) { ok = 0; break; }
            }
        }
        printf(ok ? "Yes\n" : "No\n");
    }
    return 0;
}

